// Canonical bridge key: smaller coordinate pair first
export function bridgeKey(from, to) {
  const x1 = from.x, y1 = from.y, x2 = to.x, y2 = to.y;
  if (x1 < x2 || (x1 === x2 && y1 < y2)) {
    return `${x1},${y1},${x2},${y2}`;
  }
  return `${x2},${y2},${x1},${y1}`;
}

// Check if two islands are on the same row or column
function areAligned(from, to) {
  return from.x === to.x || from.y === to.y;
}

// Check if two islands are adjacent (no other island between them on same axis)
function areAdjacent(islands, from, to) {
  if (!areAligned(from, to)) return false;
  if (from.x === to.x && from.y === to.y) return false;

  const isHorizontal = from.y === to.y;

  for (const island of islands) {
    if (island.id === from.id || island.id === to.id) continue;
    if (isHorizontal) {
      if (island.y === from.y) {
        const minX = Math.min(from.x, to.x);
        const maxX = Math.max(from.x, to.x);
        if (island.x > minX && island.x < maxX) return false;
      }
    } else {
      if (island.x === from.x) {
        const minY = Math.min(from.y, to.y);
        const maxY = Math.max(from.y, to.y);
        if (island.y > minY && island.y < maxY) return false;
      }
    }
  }
  return true;
}

// Check if adding a bridge between from and to would cross any existing bridge
function wouldCross(islands, bridges, from, to) {
  const isHorizontal = from.y === to.y;

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const bx1 = parts[0], by1 = parts[1], bx2 = parts[2], by2 = parts[3];
    const bridgeIsHorizontal = by1 === by2;

    // Only check perpendicular bridges for crossing
    if (isHorizontal === bridgeIsHorizontal) continue;

    if (isHorizontal) {
      // New bridge is horizontal, existing is vertical
      const newMinX = Math.min(from.x, to.x);
      const newMaxX = Math.max(from.x, to.x);
      const newY = from.y;
      const existMinY = Math.min(by1, by2);
      const existMaxY = Math.max(by1, by2);
      const existX = bx1;

      if (existX > newMinX && existX < newMaxX &&
          newY > existMinY && newY < existMaxY) {
        return true;
      }
    } else {
      // New bridge is vertical, existing is horizontal
      const newMinY = Math.min(from.y, to.y);
      const newMaxY = Math.max(from.y, to.y);
      const newX = from.x;
      const existMinX = Math.min(bx1, bx2);
      const existMaxX = Math.max(bx1, bx2);
      const existY = by1;

      if (newX > existMinX && newX < existMaxX &&
          existY > newMinY && existY < newMaxY) {
        return true;
      }
    }
  }
  return false;
}

// Compute current bridge counts per island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const island of islands) {
    counts.set(island.id, 0);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const x1 = parts[0], y1 = parts[1], x2 = parts[2], y2 = parts[3];

    for (const island of islands) {
      if ((island.x === x1 && island.y === y1) ||
          (island.x === x2 && island.y === y2)) {
        counts.set(island.id, (counts.get(island.id) || 0) + count);
      }
    }
  }

  return counts;
}

// Check if adding delta bridges is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Check alignment and adjacency
  if (!areAligned(from, to) || from.id === to.id) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = bridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Check max bridges
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing (only if adding bridges)
  if (delta > 0 && current === 0) {
    if (wouldCross(islands, bridges, from, to)) {
      return { valid: false, error: "Bridges would cross" };
    }
  }

  return { valid: true, error: null };
}

// Check connectivity - all islands with at least one bridge are connected
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  // Build adjacency from bridges
  const adj = new Map();
  for (const island of islands) {
    adj.set(island.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const x1 = parts[0], y1 = parts[1], x2 = parts[2], y2 = parts[3];

    let id1 = null, id2 = null;
    for (const island of islands) {
      if (island.x === x1 && island.y === y1) id1 = island.id;
      if (island.x === x2 && island.y === y2) id2 = island.id;
    }

    if (id1 !== null && id2 !== null) {
      adj.get(id1).push(id2);
      adj.get(id2).push(id1);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const current = queue.shift();
    for (const neighbor of adj.get(current) || []) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check victory condition
export function isVictory(islands, bridges) {
  if (islands.length === 0) return false;

  // Check all island counts are satisfied
  const counts = computeCurrentCounts(islands, bridges);
  for (const island of islands) {
    if ((counts.get(island.id) || 0) !== island.value) {
      return false;
    }
  }

  // Check connectivity
  if (!checkConnectivity(islands, bridges)) {
    return false;
  }

  return true;
}
