import React, { useState, useEffect, useCallback, useRef } from 'react';
import { puzzles } from './data/puzzles';
import { bridgeKey, canAddBridge, computeCurrentCounts, isVictory } from './utils/hashiLogic';

const GRID_SIZE = 40;
const SVG_WIDTH = 800;
const SVG_HEIGHT = 600;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandIdx, setCursorIslandIdx] = useState(0);
  const [errorMessage, setErrorMessage] = useState('');
  const [victory, setVictory] = useState(false);
  const [keyboardMode, setKeyboardMode] = useState(false);
  const svgRef = useRef(null);

  const currentPuzzle = puzzles[puzzleIndex];
  const islands = currentPuzzle.islands;

  // Reset when puzzle changes
  const resetGame = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setErrorMessage('');
    setVictory(false);
    setCursorIslandIdx(0);
    setKeyboardMode(false);
  }, []);

  useEffect(() => {
    resetGame();
  }, [puzzleIndex, resetGame]);

  // Check victory after bridges change
  useEffect(() => {
    if (bridges.size > 0 && isVictory(islands, bridges)) {
      setVictory(true);
    } else {
      setVictory(false);
    }
  }, [bridges, islands]);

  const clearError = () => setErrorMessage('');

  const toggleBridge = useCallback((fromIsland, toIsland, forceRemove = false) => {
    if (fromIsland.id === toIsland.id) return;

    if (forceRemove) {
      // Right-click / Ctrl+click: remove bridge entirely
      const key = bridgeKey(fromIsland, toIsland);
      const current = bridges.get(key) || 0;
      if (current > 0) {
        clearError();
        const newBridges = new Map(bridges);
        newBridges.delete(key);
        setBridges(newBridges);
      }
      setSelectedIsland(null);
      return;
    }

    // Cycle: none -> single -> double -> none
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current === 2) {
      // Remove bridge (cycle back to none)
      clearError();
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setSelectedIsland(null);
      return;
    }

    // Try to add one bridge
    const delta = 1;
    const result = canAddBridge(islands, bridges, fromIsland, toIsland, delta);
    if (!result.valid) {
      setErrorMessage(result.error);
      setSelectedIsland(null);
      return;
    }

    clearError();
    const newBridges = new Map(bridges);
    newBridges.set(key, current + delta);
    setBridges(newBridges);
    setSelectedIsland(null);
  }, [bridges, islands]);

  // Mouse click on island
  const handleIslandClick = useCallback((island, e) => {
    if (victory) return;
    const isRightClickLike = e.ctrlKey || e.metaKey;

    if (isRightClickLike && selectedIsland !== null) {
      toggleBridge(selectedIsland, island, true);
      return;
    }

    if (selectedIsland === null) {
      clearError();
      setSelectedIsland(island);
    } else {
      toggleBridge(selectedIsland, island, false);
    }
  }, [selectedIsland, victory, toggleBridge]);

  // Right-click handler
  const handleContextMenu = useCallback((island, e) => {
    e.preventDefault();
    if (victory) return;
    if (selectedIsland !== null) {
      toggleBridge(selectedIsland, island, true);
    }
  }, [selectedIsland, victory, toggleBridge]);

  // Keyboard navigation
  const handleKeyDown = useCallback((e) => {
    if (victory) return;
    const key = e.key;

    if (key === 'Escape') {
      setSelectedIsland(null);
      setKeyboardMode(false);
      clearError();
      return;
    }

    if (key === 'ArrowUp' || key === 'ArrowDown' || key === 'ArrowLeft' || key === 'ArrowRight') {
      e.preventDefault();
      setKeyboardMode(true);
      const currentIsland = islands[cursorIslandIdx];
      let bestIdx = cursorIslandIdx;
      let bestDist = Infinity;

      for (let i = 0; i < islands.length; i++) {
        if (i === cursorIslandIdx) continue;
        const other = islands[i];
        const dx = other.x - currentIsland.x;
        const dy = other.y - currentIsland.y;

        let valid = false;
        if (key === 'ArrowRight' && dx > 0 && Math.abs(dy) <= Math.abs(dx)) valid = true;
        if (key === 'ArrowLeft' && dx < 0 && Math.abs(dy) <= Math.abs(dx)) valid = true;
        if (key === 'ArrowDown' && dy > 0 && Math.abs(dx) <= Math.abs(dy)) valid = true;
        if (key === 'ArrowUp' && dy < 0 && Math.abs(dx) <= Math.abs(dy)) valid = true;

        if (valid) {
          const dist = Math.abs(dx) + Math.abs(dy);
          if (dist < bestDist) {
            bestDist = dist;
            bestIdx = i;
          }
        }
      }
      setCursorIslandIdx(bestIdx);
      return;
    }

    if (key === 'Enter') {
      setKeyboardMode(true);
      const cursorIsland = islands[cursorIslandIdx];
      if (selectedIsland === null) {
        clearError();
        setSelectedIsland(cursorIsland);
      } else {
        toggleBridge(selectedIsland, cursorIsland, false);
      }
      return;
    }
  }, [victory, cursorIslandIdx, islands, selectedIsland, toggleBridge]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  // Render bridges
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const parts = key.split(',').map(Number);
      const x1 = parts[0] * GRID_SIZE;
      const y1 = parts[1] * GRID_SIZE;
      const x2 = parts[2] * GRID_SIZE;
      const y2 = parts[3] * GRID_SIZE;

      const isHorizontal = y1 === y2;
      const offset = 4;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={x1} y1={y1} x2={x2} y2={y2}
            stroke="#0f0"
            strokeWidth="2"
          />
        );
      } else if (count === 2) {
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1} y1={y1 - offset} x2={x2} y2={y2 - offset}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1} y1={y1 + offset} x2={x2} y2={y2 + offset}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
        } else {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1 - offset} y1={y1} x2={x2 - offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1 + offset} y1={y1} x2={x2 + offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
        }
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map((island) => {
      const px = island.x * GRID_SIZE;
      const py = island.y * GRID_SIZE;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}>
          <circle
            cx={px}
            cy={py}
            r={16}
            fill="black"
            stroke={isSelected ? '#ff0' : '#0f0'}
            strokeWidth={isSelected ? 3 : 2}
            style={{ cursor: 'pointer' }}
            onClick={(e) => handleIslandClick(island, e)}
            onContextMenu={(e) => handleContextMenu(island, e)}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
            style={{ pointerEvents: 'none' }}
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  // Render keyboard cursor (rect, not circle)
  const renderCursor = () => {
    if (!keyboardMode) return null;
    const island = islands[cursorIslandIdx];
    if (!island) return null;
    const px = island.x * GRID_SIZE;
    const py = island.y * GRID_SIZE;

    return (
      <rect
        x={px - 20}
        y={py - 20}
        width={40}
        height={40}
        fill="none"
        stroke="#ff0"
        strokeWidth="2"
        strokeDasharray="4,2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div style={{ margin: 0, padding: 0 }}>
      <div style={{ padding: '8px', fontFamily: 'monospace', color: '#0f0' }}>
        <label htmlFor="puzzle-select" style={{ marginRight: '8px' }}>Puzzle:</label>
        <select
          id="puzzle-select"
          value={puzzleIndex}
          onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
        >
          {puzzles.map((p, idx) => (
            <option key={p.id} value={idx}>{p.name}</option>
          ))}
        </select>
        <button
          onClick={resetGame}
          style={{ marginLeft: '16px', background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', cursor: 'pointer' }}
        >
          Reset
        </button>
      </div>
      {errorMessage && (
        <div className="error-message" style={{ padding: '4px 8px', color: '#f00', fontFamily: 'monospace' }}>
          {errorMessage}
        </div>
      )}
      {victory && (
        <div className="victory-banner" style={{ padding: '8px', color: '#0f0', fontFamily: 'monospace', fontSize: '24px', textAlign: 'center', border: '2px solid #0f0', margin: '8px' }}>
          SOLVED!
        </div>
      )}
      <svg
        ref={svgRef}
        width={SVG_WIDTH}
        height={SVG_HEIGHT}
        style={{ display: 'block' }}
        tabIndex="0"
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
APPEOF
",
      "duration": 0.5
    }
  ]
}

